mapper.select:
SELECT a.*
from system_currency_info a left join i18n_message b on a.currency_name_i18=b.message_key
where 1=1
and b.language =#{vo.languageCode}

   and  a.currency_code  like concat('%',#{vo.currencyCode},'%')


    and b.message like concat('%',#{vo.currencyName},'%')


    and  a.currency_code in

          #{currencyCode}



    and  a.status =#{vo.status}

order by a.created_time
